#define DEFAULT_ORDER 508

typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    bool is_leaf;
    int num_keys;
} knode;

kernel void findK(    long maxheight,
                      global knode *knodes,
                      long knodes_elem,
                      global record *records,
                      global long *currKnode,
                      global long *offset,
                      global int *keys,
                      global record *ans)
{
    int bid = get_global_id(0) / get_local_size(0);
    int thid = get_global_id(0) % get_local_size(0);

    if (bid >= get_global_size(0) / get_local_size(0)) {
        return;
    }

    int i;
    long offset_val;
    long currKnode_val;

    currKnode_val = currKnode[bid];
    offset_val = offset[bid];

    for (i = 0; i < maxheight; i++) {
        if (thid < DEFAULT_ORDER + 1) {
            if ((knodes[currKnode_val].keys[thid]) <= keys[bid] && 
                (knodes[currKnode_val].keys[thid + 1] > keys[bid])) {
                if (knodes[offset_val].indices[thid] < knodes_elem) {
                    offset_val = knodes[offset_val].indices[thid];
                }
            }
        }
        currKnode_val = offset_val;
    }

    currKnode[bid] = currKnode_val;
    offset[bid] = offset_val;

    if (thid < DEFAULT_ORDER + 1) {
        if (knodes[currKnode_val].keys[thid] == keys[bid]) {
            ans[bid].value = records[knodes[currKnode_val].indices[thid]].value;
        }
    }
}

